mapper.select:
SELECT rv.*, r.res_name, r.res_code, r.res_type, r.location, e.emp_name, d.dept_name, ap.emp_name AS approvedEmpName FROM reservation rv JOIN com_resource r ON rv.res_id = r.res_id JOIN employee e ON rv.emp_id = e.emp_id JOIN department d ON e.dept_id = d.dept_id LEFT JOIN employee ap ON rv.approved_emp_id = ap.emp_id WHERE rv.com_id = #{comId}
AND r.res_type = #{resType}
AND ( UPPER(r.res_code) LIKE '%' || #{keyword} || '%' OR UPPER(r.res_name) LIKE '%' || #{keyword} || '%' )
AND rv.emp_id = #{empId}
AND rv.status = #{status}
AND rv.updated_at >= #{startDt}
AND rv.updated_at <TO_DATE(#{endDt}, 'YYYY-MM-DD') + 1
ORDER BY rv.rev_id DESC OFFSET #{pstartno} ROWS FETCH NEXT #{onepagelist} ROWS ONLY

SELECT COUNT(*)
FROM reservation rv
WHERE rv.com_id = #{comId}

    AND r.res_type = #{resType}


    AND ( UPPER(r.res_code) LIKE '%' || #{keyword} || '%'
     OR UPPER(r.res_name) LIKE '%' || #{keyword} || '%' )


    AND rv.emp_id = #{empId}


    AND rv.status = #{status}


    AND rv.updated_at >= #{startDt}


    AND rv.updated_at <TO_DATE(#{endDt}, 'YYYY-MM-DD') + 1

mapper.delete:
DELETE FROM reservation
WHERE rev_id = #{revId}
  AND status = 'WAI'

mapper.select:
SELECT NVL(SUM(quantity), 0) FROM reservation WHERE res_id = #{resId} AND status IN ('WAI','APP')
AND rev_id != #{excludeRevId}
AND start_dt < TO_TIMESTAMP(#{endDt}, 'YYYY-MM-DD"T"HH24:MI') AND end_dt > TO_TIMESTAMP(#{startDt}, 'YYYY-MM-DD"T"HH24:MI')
